-- Generated by OrchestKit Claude Plugin
-- Created: 2026-07-20

-- Router follow-on view (#3024).
--
-- The auto routers (/ork:auto, /hq-ext:auto) classify in-prompt and hand off by
-- invoking the target skill, so a handoff shows up in skill_invocation as the
-- next row in the same session. This view surfaces those pairs.
--
-- WINDOW IS LOAD-BEARING, NOT DECORATION. Sessions are long-lived and
-- multi-goal, so "the next skill in this session" is NOT the same thing as
-- "the skill the router dispatched to". Measured against real data before
-- choosing the bound: of 53 unbounded router->next pairs, the MEDIAN gap was
-- 43 minutes and the max was 27 hours — i.e. unbounded, this view mostly
-- reports "what the user happened to run later", not routing. A real handoff
-- lands in the same turn, within seconds. The 120s bound below keeps pairs
-- that can plausibly be a handoff and drops the rest.
--
-- READ THE RESULTS AS A LOWER BOUND, NOT A CENSUS. A router that answers
-- inline, routes into a forked subagent whose skill calls land under a
-- different session, or is followed by a slow human turn produces no row here.
-- Decision-level routing telemetry (goal -> chosen intent -> mutating?) is a
-- separate, still-unbuilt stream; this view is the zero-new-writers
-- approximation, not a replacement for it.
--
-- Self-pairs (router -> same router) are excluded: those are session
-- re-entries for a new goal, not a dispatch.

PRAGMA user_version = 3;

DROP VIEW IF EXISTS routing_edge;

CREATE VIEW routing_edge AS
SELECT
    a.session_id,
    a.skill        AS router,
    b.skill        AS routed_to,
    a.invoked_at   AS routed_at,
    b.invoked_at - a.invoked_at AS gap_ms
FROM skill_invocation a
JOIN skill_invocation b
  ON b.session_id = a.session_id
 AND b.invoked_at > a.invoked_at
 AND b.invoked_at = (
      SELECT MIN(c.invoked_at)
      FROM skill_invocation c
      WHERE c.session_id = a.session_id
        AND c.invoked_at > a.invoked_at
 )
WHERE a.skill IN ('ork:auto', 'hq-ext:auto')
  AND b.skill != a.skill
  AND b.invoked_at - a.invoked_at <= 120000;
